293	// openrouterProbeProjection is the routing engine's view of the openrouter
294	// credit-probe cache: a credit-exhausted map plus the two failure-mode maps
295	// surfaced by the failure-classification gate. All three maps share the
296	// same probe pass so the freshness cache is consulted exactly once per
297	// provider per routing call.
298	type openrouterProbeProjection struct {
299		CreditExhausted     map[string]routing.ProviderCreditExhaustedEvidence
300		CredentialInvalid   map[string]routing.ProviderCredentialInvalidEvidence
301		ProviderUnreachable map[string]routing.ProviderProbeUnreachableEvidence
302	}
