304	// openrouterProbeMaps refreshes the per-provider credit cache (one HTTP call
305	// at most, per TTL window, per provider) and returns the routing engine's
306	// view of credit-exhausted, credential-invalid, and provider-unreachable
307	// evidence in a single pass.
308	//
309	// Cache misses and TTL-expired entries trigger a synchronous probe; entries
310	// still inside the TTL are reused. Providers without an api key are skipped
311	// (the credential gate already surfaces that case).
312	//
313	// Failure-mode semantics:
314	//   - HasBalance=true and balance < threshold → CreditExhausted entry.
315	//   - FailureMode=credential_invalid → CredentialInvalid entry carrying the
316	//     originating HTTP status.
317	//   - FailureMode=provider_unreachable → ProviderUnreachable entry. The entry
318	//     persists only until the next probe pass: when the TTL elapses (or a
319	//     fresh attempt succeeds) the cache record is overwritten with the new
320	//     outcome, so a transient blip clears automatically (fail-open).
321	func (s *service) openrouterProbeMaps(ctx context.Context, now time.Time) openrouterProbeProjection {
322		var out openrouterProbeProjection
323		if s == nil || s.openrouterCredit == nil || s.opts.ServiceConfig == nil {
324			return out
325		}
326		cfg := s.opts.ServiceConfig
327		names := cfg.ProviderNames()
328		if len(names) == 0 {
329			return out
330		}
331		for _, name := range names {
332			pcfg, ok := cfg.Provider(name)
333			if !ok {
334				continue
335			}
336			if normalizeServiceProviderType(pcfg.Type) != "openrouter" {
337				continue
338			}
339			apiKey := strings.TrimSpace(pcfg.APIKey)
340			if apiKey == "" || !openrouterAPIKeyWellFormed(apiKey) {
341				// Credential gate is responsible for these cases; do not probe.
342				continue
343			}
344			ttl := openrouterCreditTTLFor(pcfg)
345			s.openrouterCredit.EnsureFresh(ctx, name, pcfg.BaseURL, apiKey, now, ttl)
346			rec, ok := s.openrouterCredit.Lookup(name)
347			if !ok {
348				continue
349			}
350			if rec.HasBalance {
351				threshold := openrouterCreditThresholdFor(pcfg)
352				if rec.BalanceUSD < threshold {
353					if out.CreditExhausted == nil {
354						out.CreditExhausted = map[string]routing.ProviderCreditExhaustedEvidence{}
355					}
356					out.CreditExhausted[name] = routing.ProviderCreditExhaustedEvidence{
357						BalanceUSD:   rec.BalanceUSD,
358						ThresholdUSD: threshold,
359						ObservedAt:   rec.ObservedAt,
360					}
361				}
362				continue
363			}
364			switch rec.FailureMode {
365			case openrouterCreditFailureCredentialInvalid:
366				if out.CredentialInvalid == nil {
367					out.CredentialInvalid = map[string]routing.ProviderCredentialInvalidEvidence{}
368				}
369				out.CredentialInvalid[name] = routing.ProviderCredentialInvalidEvidence{
370					HTTPStatus: rec.FailureHTTPStatus,
371					ObservedAt: rec.ObservedAt,
372				}
373			case openrouterCreditFailureProviderUnreachable:
374				if out.ProviderUnreachable == nil {
375					out.ProviderUnreachable = map[string]routing.ProviderProbeUnreachableEvidence{}
