// providerEligibilityOverridesFromCredentials inspects each configured
// provider that authenticates with an API key and builds an override map for
// the routing engine's generic ProviderEligibilityOverrides plumbing. Any
// provider with a missing or obviously unusable credential is marked with
// FilterReasonCredentialMissing so the candidate appears as eligible=false in
// the routing decision before any HTTP I/O is attempted. The probe timestamp
// is `now` — this is a config-time signal with no separate observation.
//
// The check is synchronous and side-effect free: it never issues an HTTP
// request. Server-side credential rejection (401 after dispatch) is a
// separate failure mode classified via the credit probe.
func providerEligibilityOverridesFromCredentials(cfg ServiceConfigSource, now time.Time) map[string]routing.ProviderEligibilityOverride {
	if cfg == nil {
		return nil
	}
	names := cfg.ProviderNames()
	if len(names) == 0 {
		return nil
	}
	provider, ok := cfg.(interface {
		Provider(name string) (ServiceProviderEntry, bool)
	})
	if !ok {
		return nil
	}
	out := make(map[string]routing.ProviderEligibilityOverride)
	for _, name := range names {
		pcfg, ok := provider.Provider(name)
		if !ok {
			continue
		}
		if _, missing := credentialMissingForProvider(name, pcfg); missing {
			out[name] = routing.ProviderEligibilityOverride{
				FilterReason: routing.FilterReasonCredentialMissing,
				ProbeAt:      now,
			}
		}
	}
	if len(out) == 0 {
		return nil
	}
	return out
}

// credentialMissingForProvider returns (location, true) when the named
// provider needs an API key but the configured value is unusable. location
// names the field the operator should set. The detector treats three cases
// as unusable: an empty value (or whitespace-only), an unexpanded shell
// placeholder like `${OPENROUTER_API_KEY}` (the env var was not set when
// config loaded), or an otherwise obviously malformed key (wrong prefix or
// far too short).
//
// The check is synchronous and side-effect free: it never issues an HTTP
// request. Server-side validity is out of scope here — the rejection path
// will materialize the credential_invalid reason separately.
func credentialMissingForProvider(name string, pcfg ServiceProviderEntry) (string, bool) {
	if normalizeServiceProviderType(pcfg.Type) != "openrouter" {
		return "", false
	}
	location := fmt.Sprintf("providers.%s.api_key (or OPENROUTER_API_KEY env)", name)
	key := strings.TrimSpace(pcfg.APIKey)
	if key == "" {
		return location, true
	}
	// Unexpanded shell placeholder: config loader preserves `${VAR}` verbatim
	// when the env var is unset (see internal/config/config_test.go
	// TestLoad_EnvExpansion_Unset), so the raw substring is the cleanest
	// signal that the operator's env wiring failed.
	if strings.Contains(key, "${") {
		return location, true
	}
	if !openrouterAPIKeyWellFormed(key) {
		return location, true
	}
	return "", false
}

