// TestOpenrouterUnexpandedPlaceholderTreatedAsMissing pins the bug from
// fizeau-73a00a6b: when fizeau config sets api_key to the literal string
// `${OPENROUTER_API_KEY}` and the env var is unset at config-load time, the
// config loader preserves the placeholder verbatim (see
// internal/config/config_test.go TestLoad_EnvExpansion_Unset). The credential
// gate must surface that as an ineligible openrouter candidate with
// FilterReason=credential_missing wired through the generic
// ProviderEligibilityOverrides plumbing (fizeau-458f10b0) before any HTTP
// dispatch can issue a 401.
func TestOpenrouterUnexpandedPlaceholderTreatedAsMissing(t *testing.T) {
	t.Setenv("OPENROUTER_API_KEY", "")
	svc, hits := openrouterCredentialGateService(t, "${OPENROUTER_API_KEY}")
	pcfg, _ := svc.opts.ServiceConfig.Provider("openrouter")
	srvURL, err := url.Parse(pcfg.BaseURL)
	if err != nil {
		t.Fatalf("parse base URL %q: %v", pcfg.BaseURL, err)
	}
	installPanickingOpenRouterTransport(t, srvURL.Host)

	dec, err := svc.ResolveRoute(context.Background(), RouteRequest{})
	_ = err
	var traced DecisionWithCandidates
	if dec == nil && errors.As(err, &traced) {
		dec = &RouteDecision{Candidates: traced.RouteCandidates()}
	}
	candidate := findOpenRouterCandidate(t, dec)
	if candidate.Eligible {
		t.Fatalf("openrouter candidate eligible with unexpanded ${OPENROUTER_API_KEY} placeholder: %#v", *candidate)
	}
	if candidate.FilterReason != string(routing.FilterReasonCredentialMissing) {
		t.Fatalf("openrouter FilterReason=%q, want %q", candidate.FilterReason, routing.FilterReasonCredentialMissing)
	}
	if !strings.Contains(candidate.Reason, string(routing.FilterReasonCredentialMissing)) {
		t.Fatalf("openrouter Reason=%q, want body to mention %s", candidate.Reason, routing.FilterReasonCredentialMissing)
	}
	if hits.Load() != 0 {
		t.Fatalf("openrouter HTTP hits=%d, want zero — credential gate must short-circuit before dispatch", hits.Load())
	}
}
